import ReactDOM from "react-dom/client"
import "./style.css"

const root = ReactDOM.createRoot(document.getElementById("root"))

function Navbar()
{
  return(
    <nav>
      <h1>Perfumy</h1>
      <ul>
        <li>Home | </li>
        <li>Products | </li>
        <li>About | </li>
        <li>Contact | </li>
      </ul>
    </nav>
  )
}

function Searchbar()
{
  return(
      <div class="searchbar">
            <input type="text" placeholder="Search"></input> 
        </div>
  )
}


root.render(
  <div>
    <Navbar></Navbar>

  </div>
)
